import type { FC } from 'react';
import { cn } from '@/lib/utils';
import { type IconProps, type SvgProps, sizeMap } from '../types';

export type TestFailedProps = IconProps;

const TestFailedLight: FC<SvgProps> = ({
  size,
  className,
  title,
  role,
  'aria-label': ariaLabel,
  'aria-hidden': ariaHidden,
}) => (
  <svg
    width={size}
    height={size}
    viewBox="0 0 16 16"
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    className={className}
    role={role}
    aria-label={ariaLabel}
    aria-hidden={ariaHidden}
  >
    {title ? <title>{title}</title> : null}
    <path
      fillRule="evenodd"
      clipRule="evenodd"
      d="M8 15A7 7 0 1 0 8 1a7 7 0 0 0 0 14M5.816 4.684a.8.8 0 1 0-1.131 1.132L6.869 8l-2.184 2.184a.8.8 0 0 0 1.13 1.132L8 9.13l2.185 2.185a.8.8 0 0 0 1.13-1.132L9.133 8l2.184-2.184a.8.8 0 0 0-1.132-1.132L8 6.87z"
      fill="#FFAF0F"
    />
  </svg>
);

const TestFailedDark: FC<SvgProps> = ({
  size,
  className,
  title,
  role,
  'aria-label': ariaLabel,
  'aria-hidden': ariaHidden,
}) => (
  <svg
    width={size}
    height={size}
    viewBox="0 0 16 16"
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    className={className}
    role={role}
    aria-label={ariaLabel}
    aria-hidden={ariaHidden}
  >
    {title ? <title>{title}</title> : null}
    <path
      fillRule="evenodd"
      clipRule="evenodd"
      d="M8 15A7 7 0 1 0 8 1a7 7 0 0 0 0 14M5.816 4.684a.8.8 0 1 0-1.131 1.132L6.869 8l-2.184 2.184a.8.8 0 0 0 1.13 1.132L8 9.13l2.185 2.185a.8.8 0 0 0 1.13-1.132L9.133 8l2.184-2.184a.8.8 0 0 0-1.132-1.132L8 6.87z"
      fill="#F2C55C"
    />
  </svg>
);

export const TestFailed: FC<TestFailedProps> = ({
  size = 'md',
  mode = 'light',
  className,
  'aria-label': ariaLabel,
  title,
  ...props
}) => {
  const SvgComponent = mode === 'light' ? TestFailedLight : TestFailedDark;

  return (
    <SvgComponent
      size={sizeMap[size]}
      className={cn('inline-block flex-shrink-0', className)}
      title={title}
      role={ariaLabel ? 'img' : 'presentation'}
      aria-label={ariaLabel}
      aria-hidden={!ariaLabel}
      {...props}
    />
  );
};
